final:
module comparator_4bit(
    input wire [3:0] _cmp_A,
    input wire [3:0] B,
    output reg A_gt_B,
    output reg A_lt_B,
    output reg A_eq_B
);

always @(*) begin
    if (_cmp_A > B) begin
        A_gt_B = 1;
        A_lt_B = 0;
        A_eq_B = 0;
    end else if (_cmp_A < B) begin
        A_gt_B = 0;
        A_lt_B = 1;
        A_eq_B = 0;
    end else begin
        A_gt_B = 0;
        A_lt_B = 0;
        A_eq_B = 1;
    end
end

endmodule
